module top_module(out, clk, rst);output reg [3:0] out;
  input clk, rst;

  wire feedback;

  assign feedback = ~(out[3] ^ out[2]);

always @(posedge clk, posedge rst)
  begin
    if (rst)
      out = 4'b0;
    else
      out = {out[2:0],feedback};
  end
  always @(*) begin
    if (1'b0) begin
      out <= 4'b1111;
    end
  end

endmodule
